        //        "stp": "",
        //        "stop": "",
        //        "stopTriggered": false,
        //        "stopPrice": "0",
        //        "timeInForce": "GTC",
        //        "postOnly": false,
        //        "hidden": false,
        //        "iceberg": false,
        //        "visibleSize": "0",
        //        "cancelAfter": 0,
        //        "channel": "API",
        //        "clientOid": "d602d73f-5424-4751-bef0-8debce8f0a82",
        //        "remark": null,
        //        "tags": "partner:ccxt",
        //        "isActive": true,
        //        "cancelExist": false,
        //        "createdAt": 1674149096927,
        //        "tradeType": "TRADE"
        //    }
        //
        // stop orders (fetchOpenOrders, fetchClosedOrders)
        //
        //    {
        //        "id": "vs9f6ou9e864rgq8000t4qnm",
        //        "symbol": "USDC-USDT",
        //        "userId": "613a896885d8660006151f01",
        //        "status": "NEW",
        //        "type": "market",
        //        "side": "sell",
        //        "price": null,
        //        "size": "1.00000000000000000000",
        //        "funds": null,
        //        "stp": null,
        //        "timeInForce": "GTC",
        //        "cancelAfter": -1,
        //        "postOnly": false,
        //        "hidden": false,
        //        "iceberg": false,
        //        "visibleSize": null,
        //        "channel": "API",
        //        "clientOid": "5d3fd727-6456-438d-9550-40d9d85eee0b",
        //        "remark": null,
        //        "tags": "partner:ccxt",
        //        "relatedNo": null,
        //        "orderTime": 1674146316994000028,
        //        "domainId": "kucoin",
        //        "tradeSource": "USER",
        //        "tradeType": "MARGIN_TRADE",
        //        "feeCurrency": "USDT",
        //        "takerFeeRate": "0.00100000000000000000",
        //        "makerFeeRate": "0.00100000000000000000",
        //        "createdAt": 1674146316994,
        //        "stop": "loss",
        //        "stopTriggerTime": null,
        //        "stopPrice": "0.97000000000000000000"
        //    }
        // hf order
        //    {
        //        "id":"6478cf1439bdfc0001528a1d",
        //        "symbol":"LTC-USDT",
        //        "opType":"DEAL",
        //        "type":"limit",
        //        "side":"buy",
        //        "price":"50",
        //        "size":"0.1",
        //        "funds":"5",
        //        "dealSize":"0",
        //        "dealFunds":"0",
        //        "fee":"0",
        //        "feeCurrency":"USDT",
        //        "stp":null,
        //        "timeInForce":"GTC",
        //        "postOnly":false,
        //        "hidden":false,
        //        "iceberg":false,
        //        "visibleSize":"0",
        //        "cancelAfter":0,
        //        "channel":"API",
        //        "clientOid":"d4d2016b-8e3a-445c-aa5d-dc6df5d1678d",
        //        "remark":null,
        //        "tags":"partner:ccxt",
        //        "cancelExist":false,
        //        "createdAt":1685638932074,
        //        "lastUpdatedAt":1685639013735,
        //        "tradeType":"TRADE",
        //        "inOrderBook":true,
        //        "cancelledSize":"0",
        //        "cancelledFunds":"0",
        //        "remainSize":"0.1",
        //        "remainFunds":"5",
        //        "active":true
        //    }
        //
        object marketId = this.safeString(order, "symbol");
        object timestamp = this.safeInteger(order, "createdAt");
        object feeCurrencyId = this.safeString(order, "feeCurrency");
        object cancelExist = this.safeBool(order, "cancelExist", false);
        object responseStop = this.safeString(order, "stop");
        object trigger = !isEqual(responseStop, null);
        object stopTriggered = this.safeBool(order, "stopTriggered", false);
        object isActive = this.safeBool2(order, "isActive", "active");
        object responseStatus = this.safeString(order, "status");
        object status = null;
        if (isTrue(!isEqual(isActive, null)))
        {
            if (isTrue(isEqual(isActive, true)))
            {
                status = "open";
            } else
            {
                status = "closed";
            }
        }
        if (isTrue(trigger))
        {
            if (isTrue(isEqual(responseStatus, "NEW")))
            {
                status = "open";
            } else if (isTrue(!isTrue(isActive) && !isTrue(stopTriggered)))
            {
                status = "cancelled";
            }
        }
        if (isTrue(cancelExist))
        {
            status = "canceled";
        }
        if (isTrue(isEqual(responseStatus, "fail")))
        {
            status = "rejected";
        }
        return this.safeOrder(new Dictionary<string, object>() {
            { "info", order },
            { "id", this.safeStringN(order, new List<object>() {"id", "orderId", "newOrderId", "cancelledOrderId"}) },
            { "clientOrderId", this.safeString(order, "clientOid") },
            { "symbol", this.safeSymbol(marketId, market, "-") },
            { "type", this.safeString(order, "type") },
            { "timeInForce", this.safeString(order, "timeInForce") },
            { "postOnly", this.safeBool(order, "postOnly") },
            { "side", this.safeString(order, "side") },
            { "amount", this.safeString(order, "size") },
            { "price", this.safeString(order, "price") },
            { "triggerPrice", this.safeNumber(order, "stopPrice") },
            { "cost", this.safeString(order, "dealFunds") },
            { "filled", this.safeString(order, "dealSize") },
            { "remaining", null },
            { "timestamp", timestamp },
            { "datetime", this.iso8601(timestamp) },
            { "fee", new Dictionary<string, object>() {
                { "currency", this.safeCurrencyCode(feeCurrencyId) },
                { "cost", this.safeNumber(order, "fee") },
            } },
            { "status", status },
            { "lastTradeTimestamp", null },
            { "average", this.safeString(order, "avgDealPrice") },
            { "trades", null },
        }, market);
    }

    public virtual object parseUtaOrder(object order, object market = null)
    {
        //
        // createOrder
        //     {
        //         "orderId": "426319129738321920",
        //         "tradeType": "SPOT",
        //         "ts": 1774455603216000000,
        //         "clientOid": "b896c118-a674-4863-baf4-a9ea3cd696c5"
        //     }
        //
        // fetchOrder
        //     {
        //         "orderId": "426319129738321920",
        //         "symbol": "ETH-USDT",
        //         "orderType": "LIMIT",
        //         "side": "BUY",
        //         "size": "0.001",
        //         "price": "1000",
        //         "timeInForce": "GTC",
        //         "tags": "partner:ccxt",
        //         "orderTime": 1774455603156417582,
        //         "stp": "",
        //         "cancelAfter": null,
        //         "postOnly": false,
        //         "reduceOnly": false,
        //         "triggerDirection": "",
        //         "triggerPrice": "",
        //         "triggerPriceType": "",
        //         "tpTriggerPrice": "",
        //         "tpTriggerPriceType": "",
        //         "slTriggerPrice": "",
        //         "slTriggerPriceType": "",
        //         "filledSize": "0",
        //         "avgPrice": "0",
        //         "fee": "0",
        //         "feeCurrency": "USDT",
        //         "tax": "0",
        //         "updatedTime": 1774455603371523690,
        //         "triggerOrderId": "",
        //         "cancelReason": "",
        //         "cancelSize": "0",
        //         "clientOid": "b896c118-a674-4863-baf4-a9ea3cd696c5",
        //         "sizeUnit": "BASECCY",
        //         "tradeType": "SPOT",
        //         "tradeId": "",
        //         "status": 2
        //     }
        //
        object marketId = this.safeString(order, "symbol");
        market = this.safeMarket(marketId, market);
        object symbol = getValue(market, "symbol");
        object timestamp = this.safeIntegerProduct2(order, "orderTime", "ts", 0.000001);
        object lastUpdateTimestamp = this.safeIntegerProduct(order, "updatedTime", 0.000001);
        object rawTimeInForce = this.safeString(order, "timeInForce");
        object amount = null;
        object cost = null;
        object sizeUnit = this.safeString(order, "sizeUnit");
        object size = this.safeString(order, "size");
        object rawStatus = this.safeString(order, "status");
        object average = this.safeString(order, "avgPrice");
        object filled = this.safeString(order, "filledSize"); // might be in base or quote, need to check sizeUnit
        if (isTrue(isTrue((isEqual(sizeUnit, "BASECCY"))) || isTrue((isEqual(sizeUnit, "UNIT")))))
        {
            amount = size;
        } else
        {
            cost = filled;
            filled = Precise.stringDiv(filled, average);
            filled = this.amountToPrecision(symbol, filled);
        }
        object fee = new Dictionary<string, object>() {
            { "currency", this.safeCurrencyCode(this.safeString(order, "feeCurrency")) },
            { "cost", this.safeString(order, "fee") },
        };
        return this.safeOrder(new Dictionary<string, object>() {
            { "id", this.safeString(order, "orderId") },
            { "clientOrderId", this.safeString(order, "clientOid") },
            { "symbol", symbol },
            { "type", this.safeStringLower(order, "orderType") },
            { "timeInForce", this.parseOrderTimeInForce(rawTimeInForce) },
            { "postOnly", this.safeBool(order, "postOnly") },
            { "reduceOnly", this.safeBool(order, "reduceOnly") },
            { "side", this.safeStringLower(order, "side") },
            { "amount", amount },
            { "price", this.safeString(order, "price") },
            { "triggerPrice", this.safeString2(order, "stopPrice", "triggerPrice") },
            { "cost", cost },
            { "filled", filled },
            { "remaining", null },
            { "timestamp", timestamp },
            { "datetime", this.iso8601(timestamp) },
            { "fee", fee },
            { "status", this.parseOrderStatus(rawStatus) },
            { "lastTradeTimestamp", null },
            { "lastUpdateTimestamp", lastUpdateTimestamp },
            { "average", average },
            { "trades", null },
            { "stopLossPrice", this.safeString(order, "slTriggerPrice") },
            { "takeProfitPrice", this.safeString(order, "tpTriggerPrice") },
            { "info", order },
        }, market);
    }

    public virtual object parseOrderTimeInForce(object timeInForce)
    {
        object timeInForces = new Dictionary<string, object>() {
            { "GTC", "GTC" },
            { "IOC", "IOC" },
            { "FOK", "FOK" },
            { "GTT", "GTD" },
        };
        return this.safeString(timeInForces, timeInForce, timeInForce);
    }

    public virtual object parseOrderStatus(object status)
    {
        object statuses = new Dictionary<string, object>() {
            { "0", "open" },
            { "1", "open" },
            { "2", "open" },
            { "3", "closed" },
            { "4", "open" },
            { "5", "canceled" },
            { "6", "closed" },
        };
        return this.safeString(statuses, status, status);
    }

